"""This module provides functions for structural checks and calculations
according to the EN 1992-1-1:2004 standard for concrete structures.
"""

from structuralcodes.codes.ec2_2004 import _concrete_material_properties as mat
from structuralcodes.codes.ec2_2004 import _section_7_3_crack_control as cc
from structuralcodes.codes.ec2_2004 import shear
from structuralcodes.codes.ec2_2004._section_7_3_crack_control import As_min, k, kc_rect_area

from fhecor_structuralcodes.EN1992_1_1_2004.article_6_ec2 import Asw_s_required
from fhecor_structuralcodes.EN1992_1_1_2004.article_9_ec2 import (
    As_max_beams,
    As_min_beams,
    Ash_min_walls,
    Asv_max_walls,
    Asv_min_walls,
    Asw_min_beams,
)
from fhecor_structuralcodes.log_printer import Log


def crack_width(  # noqa: PLR0912, PLR0915
    b,
    h,
    fck,
    c,
    sigma_s,
    As,
    phi_eq,
    ds=None,
    Ap=None,
    phi_p=None,
    dp=None,
    Ac_eff=None,
    xi=None,
    Es=None,
    x=None,
    load_duration=None,
    reinf_spacing=None,
    bond_type=None,
    eps_r=None,
):
    """7.3.4 Calculation of crack widths according to EN 1992-1-1:2004.

    Parameters
    ----------
    b: float
        Width of the section (mm).
    h: float
        Height of the section (mm).
    fck : float
        Characteristic compressive strength of concrete (MPa).
    c : float
        Cover (mm).
    sigma_s : float
        Tensile stress in the reinforcement (MPa).
    As : float
        Area of longitudinal reinforcement (mm²).
    phi_eq : float
        Equivalent diameter of longitudinal reinforcement (mm).
    ds : float
        Effective depth of passive reinforcement (mm) [def. h-c-phi_s/2].
    Ap : float, optional
        Area of prestressing steel (mm²). Default is 0.
    phi_p : float, optional
        Diameter of prestressing steel (mm). Default is 0.
    dp : float
        Effective depth of prestressing steel (mm) [def. h-c-phi_p/2].
    Ac_eff : float, optional
        Effective area of concrete in tension surrounding the reinforcement or prestressing tendons of depth, hc,ef.
        If None, it is calculated for rectangular section.
    xi : float, optional
        Ratio of bond strength according to Table 6.2. Default is for ribbed bars ≤ C50/60.
    Es : float, optional
        Modulus of elasticity of steel (MPa). Default is 200,000 MPa.
    x : float, optional
        depth of neutral axis w/respect to the compressed fibre (mm). Default is 0.5h for bending.
    load_duration : str, optional
        Load duration for kt ['short', 'long']. Default is 'long'.
    reinf_spacing : float, optional
        spacing of the reinforcement (mm) used for choose sr_max equation. Default is spacing < 5(c+phi_s/2).
    bond_type : str, optional
        Type of bond ['bond', 'plain'] for k1. Default is 'bond'.
    eps_r : float, optional
        ratio eps2/eps1 for k2 where eps1 is the greater and eps2 is the lesser strain
        at the boundaries of the section. eps_r=0 for bending and eps_r=1 for pure
        tension (def. bending).



    Returns:
    -------
    (results, log): tuple
    """
    log = []
    results = {}

    # Check inputs and set defaults
    log.append(Log('7.3.4 Calculation of crack widths according to EN 1992-1-1:2004\n', color='cyan', upper_case=True))
    log.append(Log('Assumptions', color='cyan', upper_case=True))
    if Ap is None:
        Ap = 0
        phi_p = 10
        dp = 0
        log.append(Log('- No prestressing steel -> Ap=0, phi_p=0, dp=0', indent=1))
    if xi is None:
        xi = 0.7
        log.append(Log('- xi=0.7 -> ribbed bars ≤ C50/60', indent=1))
    elif xi > 0.8 or xi < 0.0:
        raise ValueError('xi must be 0.6,0.7,0.8,0.3,0,5,0.15,0.25,0.3,0.35')
    if Es is None:
        Es = 200000
        log.append(Log('- Es=200000 MPa', indent=1))
    if x is None:
        x = 0.5 * h
        log.append(Log('x=0.5*h -> bending', indent=1))
    if load_duration not in [None, 'short', 'long']:
        raise ValueError("load_duration must be 'short' or 'long'")
    if load_duration is None:
        load_duration = 'long'
        log.append(Log('- load_duration=long', indent=1))
    if reinf_spacing is None:
        reinf_spacing = 0
        log.append(Log('- reinf_spacing < 5(c+phi/2)  -> sr_max eq. (7.11)', indent=1))
    if bond_type not in [None, 'bond', 'plain']:
        raise ValueError("bond_type must be 'bond' or 'plain'")
    if bond_type is None:
        bond_type = 'bond'
        log.append(Log('- bond_type=bond', indent=1))
    if eps_r is None:
        eps_r = 0
        log.append(Log('- eps_r=0 -> bending', indent=1))
    # effective depth of the section
    if ds is None:
        ds = h - c - phi_eq / 2
    if dp is None:
        dp = h - c - phi_p / 2
    d = (ds * As + dp * Ap) / (As + Ap)  # effective depth mm

    fctm = mat.fctm(fck)  # mean compressive strength of concrete
    Ecm = mat.Ecm(mat.fcm(fck))  # mean elastic modulus of concrete

    if Ac_eff is None:
        log.append(Log('- Ac_eff for rectangular section', indent=1))
        Ac_eff = cc.hc_eff(h, d, x) * b  # effective area of the section

    xi1 = cc.xi1(xi, phi_p, phi_eq)
    rho_p_eff = cc.rho_p_eff(As, xi1, Ap, Ac_eff)

    # Eq. (7.11) (7.14)
    if reinf_spacing > 5 * (
        c + phi_eq / 2
    ):  # bonded reinforcement exceeds 5(c+phi/2) or where there is no bonded reinforcement at all
        sr_max = cc.sr_max_far(h, x)  # Eq. (7.14).
    else:
        k1 = cc.k1(bond_type)
        k2 = cc.k2(eps_r)
        k3 = cc.k3()
        k4 = cc.k4()
        sr_max = cc.sr_max_close(
            c, phi_eq, rho_p_eff, k1, k2, k3, k4
        )  # maximum crack spacing (EN 1992-1-1:2004, eq. (7.11))

    # Eq. (7.9)
    fct_eff = fctm
    kt = cc.kt(load_duration)
    alpha_e = cc.alpha_e(Es, Ecm)

    eps_sm_eps_cm = cc.eps_sm_eps_cm(sigma_s, alpha_e, rho_p_eff, kt, fct_eff, Es)

    # Eq. (7.8)
    wk = cc.wk(sr_max, eps_sm_eps_cm)  # crack width (EN 1992-1-1:2004, eq. (7.8))

    # Store results in dictionary
    results['wk'] = wk
    results['sr_max'] = sr_max
    results['eps_sm_eps_cm'] = eps_sm_eps_cm
    results['fct_eff'] = fct_eff
    results['kt'] = kt
    results['alpha_e'] = alpha_e
    results['rho_p_eff'] = rho_p_eff
    results['As'] = As
    results['Ap'] = Ap
    results['xi1'] = xi1
    results['Ac_eff'] = Ac_eff
    results['Es'] = Es
    results['k1'] = k1
    results['k2'] = k2
    results['k3'] = k3
    results['k4'] = k4

    # Log messages
    log.append(Log('\nCRACK WIDTH, wk - EXPRESSION (7.8):', color='cyan'))
    log.append(Log(f'wk = {wk:0.2f} mm', indent=0))

    log.append(Log('\nSTRAIN DIFFERENCE (epsilon_sm - epsilon_cm) - EXPRESSION (7.9):', color='cyan'))
    log.append(Log(f'Sr_max = {sr_max:0.2f} mm', indent=1))
    if reinf_spacing > 5 * (c + phi_eq / 2):
        log.append(Log(f'h = {h:0.2f} mm', indent=2))
        log.append(Log(f'x = {x:0.2f} mm', indent=2))
    else:
        log.append(Log(f'k3 = {k3:0.2f}', indent=2))
        log.append(Log(f'c = {c:0.2f} mm', indent=2))
        log.append(Log(f'k1 = {k1:0.2f}', indent=2))
        log.append(Log(f'k2 = {k2:0.2f}', indent=2))
        log.append(Log(f'k4 = {k4:0.3f}', indent=2))
        log.append(Log(f'phi_eq = {phi_eq:0} mm', indent=2))
        log.append(Log(f'rho_p_eff = {rho_p_eff:0.2f}', indent=2))

    log.append(Log('\nMAXIMUM CRACK SPACING - EXPRESSION (7.11/14):', color='cyan'))
    log.append(Log(f'eps_sm_eps_cm = {eps_sm_eps_cm * 1e3:0.3f} mm/m', indent=1))
    log.append(Log(f'sigma_s = {sigma_s:0.2f} MPa', indent=2))
    log.append(Log(f'kt= {kt:0.1f}', indent=2))
    log.append(Log(f'fct_eff = {fct_eff:0.2f} MPa', indent=2))
    log.append(Log(f'rho_p_eff = {rho_p_eff:0.2f}', indent=2))
    log.append(Log(f'As = {As:0.2f} mm²', indent=3))
    log.append(Log(f'Ap = {Ap:0.2f} mm²', indent=3))
    log.append(Log(f'xi1 = {xi1:0.2f}', indent=3))
    log.append(Log(f'Ac_eff = {Ac_eff / 100:0.2f} cm²', indent=3))
    log.append(Log(f'alpha_e= {alpha_e:0.2f}', indent=2))
    log.append(Log(f'Es= {Es:0.2f} MPa', indent=2))

    return results, log


def shear_cheks(
    ved: float,
    fck: float,
    fyk: float,
    asw: float,
    s: float,
    z: float,
    theta: float,
    d: float,
    asl: float,
    bw: float,
    ned: float,
    Ac: float,
    sismic_comb: bool,
    CE: bool = False,
):
    """Realiza las comprobaciones de cortante en una sección estructural.

    Parámetros
    ----------
    ved : float
        Esfuerzo de corte de diseño (N).
    fck : float
        Resistencia característica del hormigón (MPa).
    fyk : float
        Resistencia de fluencia del acero (MPa).
    asw : float
        Área del armado transversal (mm²).
    s : float
        Distancia o espaciado (mm).
    z : float
        Brazo mecánico (mm).
    theta : float
        Ángulo de la biela (deg).
    d : float
        Canto útil (mm).
    asl : float
        Área del armado longitudinal (mm²).
    bw : float
        Ancho de la sección (mm).
    ned : float
        Axil positivo en compresión (N).
    Ac : float
        Área de hormigón (mm²).
    sismic_comb : bool, opcional
        Indicador de combinación sísmica (por defecto False).
    CE : bool, opcional
        Adaptación a código estructural (por defecto False).
    """
    log = []
    results = {}

    if sismic_comb:
        gamma_c = 1.3 if CE else 1.2
        gamma_s = 1.0
    else:
        gamma_c = 1.5
        gamma_s = 1.15

    shear._theta(theta, 1, 2.5)

    # without reinforcement
    log.append(Log('6.2.2 MEMBERS NOT REQUIRING DESIGN SHEAR REINFORCEMENT:', color='cyan', upper_case=True))

    VRdc = shear.VRdc(fck, d, asl, bw, ned, Ac, fck / gamma_c)
    VEdmax = shear.VEdmax_unreinf(bw, d, fck, fck / gamma_c)
    # vmax = min(VEdmax, VRdc)
    if ved > VRdc:
        log.append(Log(f'VRdc [kN] = {VRdc * 1e-3:0.1f} < Ved [kN] = {ved * 1e-3:0.1f}', indent=1))
        log.append(Log('Warning! Transversal reinforcement is required following 6.2.3.', color='yellow', indent=1))
    else:
        log.append(
            Log(
                (
                    f'VRdc [kN] = {VRdc * 1e-3:0.1f} >= Ved [kN] = {ved * 1e-3:0.1f} - '
                    'OK. No transversal reinforcement is needed.'
                ),
                color='green',
                indent=1,
            )
        )
        if ved > VEdmax:
            log.append(Log(f'VEdmax [kN] = {VEdmax * 1e-3:0.1f} < Ved [kN] = {ved * 1e-3:0.1f}', indent=1))
            log.append(Log('Error! Strut failure.', color='red', indent=2))
        else:
            log.append(
                Log(
                    f'VEdmax [kN] = {VEdmax * 1e-3:0.1f} >= Ved [kN] = {ved * 1e-3:0.1f} - OK.', color='green', indent=1
                )
            )

    # with reinforcement
    log.append(Log('\n6.2.3 MEMBERS REQUIRING DESIGN SHEAR REINFORCEMENT:', color='cyan', upper_case=True))
    Vrd_s = shear.VRds(asw, s, z, theta, fyk, 90, gamma_s)
    VRdmax = shear.VRdmax(bw, z, fck, theta, ned, Ac, fck / gamma_c, 90)
    _Asw_s = Asw_s_required(ved, z, theta, fyk, 90, gamma_s)
    log.append(Log(f'Vrd_s [kN] = {Vrd_s * 1e-3:0.1f}', indent=1))

    if ved > VRdmax:
        log.append(Log(f'VRdmax [kN] = {VRdmax * 1e-3:0.1f} < Ved [kN] = {ved * 1e-3:0.1f}', indent=1))
        log.append(Log('Error! Strut failure.\n', color='red', indent=2))
    else:
        log.append(
            Log(f'VRdmax [kN] = {VRdmax * 1e-3:0.1f} >= Ved [kN] = {ved * 1e-3:0.1f} - OK.\n', color='green', indent=1)
        )

    if ved < VRdc:
        log.append(
            Log(
                f'Ved [kN] = {ved * 1e-3} < {VRdc * 1e-3:0.1f} - OK. No transversal reinforcement is needed.',
                color='green',
                indent=1,
            )
        )
    elif ved < Vrd_s:
        log.append(Log(f'Ved [kN] = {ved * 1e-3} < {Vrd_s * 1e-3:0.1f} - OK.', color='green', indent=1))
        log.append(
            Log(
                f'Asw/s disposed ({asw / s * 10:0.2f} cm²/m) > As required ({_Asw_s * 10:0.2f} cm²/m)',
                color='green',
                indent=1,
            )
        )
    else:
        log.append(Log(f'Ved [kN] = {ved * 1e-3} > {Vrd_s * 1e-3:0.1f}', color='red', indent=1))
        log.append(
            Log(
                f'Warning! Asw disposed ({asw / s * 10:0.2f} cm²/m) < As required ({_Asw_s * 10:0.2f} cm²/m)',
                color='red',
                indent=1,
            )
        )

    # Store results in dictionary
    results['VEdmax'] = VEdmax
    results['VRdc'] = VRdc
    results['VRdmax'] = VRdmax
    results['Vrd_s'] = Vrd_s
    results['Asw_s'] = _Asw_s

    return results, log


def min_max_reinforcement_rectangular_beams(
    fck, fyk, b, h, *, gamma_s=1.15, d=None, Ned=0, A_ct=None, sigma_s=None, fct_eff=None, _k=None, _kc=None
):
    """Calculate de minimum and maximum reinforcement in rectangular beams."""
    log = []

    # Chapter 7.3
    log.append(Log('\n\n-------RECTANGULAR BEAMS-------', color='cyan'))
    log.append(Log('7.3 CRACK CONTROL', color='cyan', upper_case=True))
    log.append(Log('7.3.2 Minimum reinforcement areas:', color='cyan'))
    if sigma_s is None:
        sigma_s = fyk / gamma_s

    if fct_eff is None:
        fct_eff = mat.fctm(fck)

    if _k is None:
        _k = max(k(b), k(h))

    if _kc is None:
        _kc = kc_rect_area(h, b, fct_eff, Ned)

    if A_ct is None:
        A_ct = b * h * 0.5

    As_min_chapter_7 = As_min(A_ct, sigma_s, fct_eff, _k, _kc)
    log.append(Log(f'As min = {(As_min_chapter_7 * 1e-2):.2f} cm²', indent=1))
    log.append(Log(f'- sigma_s = {sigma_s:.1f} MPa', indent=1))
    log.append(Log(f'- fct_eff = {fct_eff:.2f} MPa', indent=1))
    log.append(Log(f'- k = {_k}', indent=1))
    log.append(Log(f'- kc = {_kc}', indent=1))
    log.append(Log(f'- Ned = {Ned:.1f} (positive in compression)', indent=2))
    log.append(Log(f'- A_ct = {A_ct * 1e-6:.2f} m²', indent=1))

    # Chapter 9

    if d is None:
        d = h - 60

    bl = b  # in rectangular beams, bl=b
    if bl is None:
        bl = b
    As_min_beams_chapter_9 = As_min_beams(mat.fctm(fck), fyk, b, h - 50)
    As_max_beams_chapter_9 = As_max_beams(b * h)
    Asw_min_beams_chapter_9 = Asw_min_beams(fck, fyk, b, 90, fctm=mat.fctm(fck))
    log.append(Log('\n9.2 BEAMS', color='cyan', upper_case=True))
    log.append(Log('9.2.1 Longitudinal reinforcement:', color='cyan'))
    log.append(Log(f'As min = {(As_min_beams_chapter_9 * 1e-2):.2f} cm²', indent=1))
    log.append(Log(f'- bl = {bl:.1f} mm', indent=2))
    log.append(Log(f'- d = {d:.1f} mm', indent=2))
    log.append(Log(f'- fctm = {mat.fctm(fck):.2f} MPa', indent=2))
    log.append(Log(f'- fyk = {fyk:.1f} MPa', indent=2))
    log.append(Log(f'As max = {(As_max_beams_chapter_9 * 1e-2):.2f} cm²', indent=1))
    log.append(Log('9.2.2 Shear reinforcement:', color='cyan'))
    log.append(Log(f'Asw min = {(Asw_min_beams_chapter_9 * 10):.2f} cm²/m', indent=1))
    log.append(Log(f'- fck = {fck:.1f} MPa', indent=2))
    log.append(Log(f'- fyk = {fyk:.1f} MPa', indent=2))
    log.append(Log(f'- bw = {b:.1f} mm', indent=2))
    log.append(Log(f'- alpha = {90:.1f} º', indent=2))

    return log


def min_max_reinforcement_walls(
    fck, fyk, thk_wall, *, gamma_s=1.15, Ned=0, A_ct=None, sigma_s=None, fct_eff=None, _k=None, _kc=None
):
    """Get a detailed log with the maximum and minimum reinforcement for walls."""
    b = 1000  # values of reinforcement per linear meter of wall
    log = []

    # Chapter 7.3
    if sigma_s is None:
        sigma_s = fyk / gamma_s
    if fct_eff is None:
        fct_eff = mat.fctm(fck)
    if _k is None:
        _k = max(k(b), k(thk_wall))
    if _kc is None:
        _kc = kc_rect_area(thk_wall, b, fct_eff, Ned)
    if A_ct is None:
        A_ct = b * thk_wall * 0.5
    log.append(Log('7.3 CRACK CONTROL', color='cyan', upper_case=True))
    log.append(Log('7.3.2 Minimum reinforcement areas:', color='cyan'))
    As_min_chapter_7 = As_min(A_ct, sigma_s, fct_eff, _k, _kc)
    log.append(Log(f'As min = {(As_min_chapter_7 * 1e-2):.2f} cm2', indent=1))
    log.append(Log(f'sigma_s = {sigma_s:.1f} MPa', indent=2))
    log.append(Log(f'fct_eff = {fct_eff:.2f} MPa', indent=2))
    log.append(Log(f'k = {_k}', indent=2))
    log.append(Log(f'kc = {_kc}', indent=2))
    log.append(Log(f'Ned = {Ned:.1f} kN (positive in compression)', indent=3))
    log.append(Log(f'A_ct = {A_ct * 1e-6:.2f} m2', indent=2))

    # Chapter 9
    Ash_min_walls_chapter_9 = Ash_min_walls(
        b * thk_wall, fyk=fyk, thk_wall=thk_wall, tall_wall=True, close_joints=False
    )
    Asv_min_t, Asv_min_c = Asv_min_walls(b * thk_wall, fyk=fyk, fyd=fyk / gamma_s, fcd=fck / 1.5)
    Asv_max_walls_chapter_9 = Asv_max_walls(b * thk_wall)

    log.append(Log('\n9.6 Walls', color='cyan', upper_case=True))
    log.append(Log('9.6.2 Vertical reinforcemen:', color='cyan'))
    log.append(Log(f'Asv_t min = {(Asv_min_t * 1e-2):.2f} cm2/m (tensile face)', indent=1))
    log.append(Log(f'Asv_c min = {(Asv_min_c * 1e-2):.2f} cm2/m (compression face)', indent=1))
    log.append(Log(f'Asv max = {(Asv_max_walls_chapter_9 * 1e-2):.2f} cm2/m', indent=1))
    log.append(Log('9.6.3 Horizontal reinforcement:', color='cyan'))
    log.append(Log(f'Ash min = {(Ash_min_walls_chapter_9 * 1e-2):.2f} cm2/face', indent=1))
    return log


